Single.Single:
// ==========================================================================
// 1. GESTION DE L'ENABLE GÉNÉRAL & SÉCURITÉ DE REPLI
// ==========================================================================
IF NOT Enable THEN
    // Mise en sécurité et réinitialisation des commandes matérielles
    Out_PresetCmd       := 16#0000;
    Out_PresetValue     := 0;

    // On force l'arrêt d'urgence par sécurité si le bloc est désactivé
    EmergencyStop       := TRUE; 

    // On fige/remet à zéro les mesures pour l'IHM
    ActualSpeedFiltered := 0.0;
    // Note: On peut choisir de conserver la dernière position connue ou mettre 0.0 selon le besoin process

    LastHomingTrigger   := HomingTrigger;
    RETURN; // Sortie immédiate du bloc, le reste du code n'est pas exécuté
END_IF

// ==========================================================================
// 2. EXÉCUTION DU TRAITEMENT STANDARD (SI ENABLE = TRUE)
// ==========================================================================

// Calcul du temps de cycle
GetCycleTime();

// Traitement du sens de rotation mécanique
IF InvertDirection THEN
    LocalRawPos := 16#FFFFFFFF - In_PosValue; 
ELSE
    LocalRawPos := In_PosValue;
END_IF

// LOGIQUE DU HOMING / PRESET (Niveau de l'eau)
IF HomingTrigger AND NOT LastHomingTrigger THEN
    Out_PresetValue := REAL_TO_UDINT(WaterLevelOffset * Config_PulsePerMeter);
    Out_PresetCmd   := 16#0001; 
ELSE
    Out_PresetCmd   := 16#0000;
END_IF
LastHomingTrigger := HomingTrigger;

// DIAGNOSTIC ALARMES
EncoderError := (In_Alarms <> 0);

// PIPELINE MISE À L'ÉCHELLE (ax + b)
ScaleStage(
    CurrentRawPos  := LocalRawPos,
    OffsetValueB   := 0.0, 
    EnableTeach    := TeachActive,
    StartTeachPos  := TeachStartRaw,
    EndTeachPos    := TeachEndRaw,
    RealDistMeters := TeachRealDistance,
    PulsePerMeter  := Config_PulsePerMeter
);
ActualPositionM := ScaleStage.PositionMeters;

// PIPELINE SÉCURITÉ & VITESSE
SafetyStage(
    RawSpeed      := In_SpdValue,
    MaxSpeedLimit := MaxSpeedThreshold,
    CycleTimeS    := GetCycleTime.CycleTimeS
);
ActualSpeedFiltered := SafetyStage.FilteredSpeed;

// L'arrêt d'urgence tombe si survitesse ou si le codeur remonte un défaut matériel
EmergencyStop       := SafetyStage.OverspeedTrip OR EncoderError;
// 3. LOGIQUE DU HOMING / PRESET (Niveau de l'eau)
// Quand on valide le Homing, on prépare les mots RxPDO pour le codeur EtherCAT
IF HomingTrigger AND NOT LastHomingTrigger THEN
    // On convertit la position "Niveau de l'eau" en points codeur pour flasher le hard
    Out_PresetValue := REAL_TO_UDINT(WaterLevelOffset * Config_PulsePerMeter);
    Out_PresetCmd   := 16#0001; // Code d'écriture du Preset (dépend de la doc du codeur)
ELSE
    Out_PresetCmd   := 16#0000;
END_IF
LastHomingTrigger := HomingTrigger;

// 4. DIAGNOSTIC ALARMES (Simplifié pour l'exemple)
EncoderError := (In_Alarms <> 0);

// 5. PIPELINE MISE À L'ÉCHELLE (ax + b)
ScaleStage(
    CurrentRawPos  := LocalRawPos,
    OffsetValueB   := 0.0, // Géré par le Homing matériel du codeur
    EnableTeach    := TeachActive,
    StartTeachPos  := TeachStartRaw,
    EndTeachPos    := TeachEndRaw,
    RealDistMeters := TeachRealDistance,
    PulsePerMeter  := Config_PulsePerMeter // Variable In_Out persistante
);
ActualPositionM := ScaleStage.PositionMeters;

// 6. PIPELINE SÉCURITÉ & VITESSE
SafetyStage(
    RawSpeed      := In_SpdValue,
    MaxSpeedLimit := MaxSpeedThreshold,
    CycleTimeS    := GetCycleTime.CycleTimeS
);
ActualSpeedFiltered := SafetyStage.FilteredSpeed;
EmergencyStop       := SafetyStage.OverspeedTrip OR EncoderError; // Si alarme = Arret treuil
